import { DOCUMENT } from '@angular/common';
import { HttpClient } from '@angular/common/http';
import {
  Component,
  computed,
  DestroyRef,
  effect,
  HostBinding,
  inject,
  OnInit,
  RendererFactory2,
  signal,
} from '@angular/core';
import { firstValueFrom, Subject } from 'rxjs';
import { skip, take, takeUntil } from 'rxjs/operators';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { TranslatePipe } from '@ngx-translate/core';

import { ThemeDataService } from '../../services/theme-data.service';
import { ClientDataService } from '../../../features/clients/services/client-data.service';
import { ClientResponse, ThemeResponse } from '../../../api';
import { isDefined, isNullOrUndefined } from '../../utils';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

@Component({
  selector: 'app-theme',
  imports: [ProgressSpinnerModule, TranslatePipe],
  templateUrl: './theme.component.html',
  styleUrls: ['./theme.component.scss'],
})
export class ThemeComponent implements OnInit {
  private static readonly THEME_OPERATION_TIMEOUT_MS = 5000;
  private static readonly FONT_LOAD_TIMEOUT_MS = 3000;
  private readonly destroyRef = inject(DestroyRef);
  private readonly themeService = inject(ThemeDataService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly renderer = inject(RendererFactory2).createRenderer(
    null,
    null,
  );
  private readonly document = inject(DOCUMENT);
  private readonly http = inject(HttpClient);
  readonly loading = signal(false);
  private static readonly LOADING_DEBOUNCE_MS = 200;
  readonly hasNativeCssVariableSupport = computed(() => {
    const window = this.document.defaultView;
    return window?.CSS?.supports?.('(--a: 0)') === true;
  });

  @HostBinding('class') classes = '';
  private previousClientId: string | undefined = undefined;
  private previousThemeId: string | undefined = undefined;
  private readonly cancelPendingThemeRequest$ = new Subject<void>();
  private readonly currentHostname =
    this.document.location?.hostname ??
    this.document.defaultView?.location.hostname ??
    'localhost';

  constructor() {
    effect(() => {
      // Use selected client if available; otherwise use preview client (for context-selection page)
      const selectedClient = this.clientDataService.getSelectedClient();
      const clientToUse =
        selectedClient ?? this.clientDataService.getPreviewClient();

      if (isDefined(clientToUse)) {
        const themeId = this.getThemeId(clientToUse);

        // Guard: Don't change theme if client was updated without theme data
        // This prevents partial client updates from resetting to default theme
        const isClientUpdateWithoutTheme =
          clientToUse.id === this.previousClientId &&
          !isDefined(clientToUse.theme?.id) &&
          isDefined(this.previousThemeId);

        if (isClientUpdateWithoutTheme) {
          return;
        }

        if (
          clientToUse.id !== this.previousClientId ||
          themeId !== this.previousThemeId
        ) {
          // Cancel any pending theme requests before starting a new one
          this.cancelPendingThemeRequest$.next();
          this.updateTheme(themeId);
          this.previousClientId = clientToUse.id;
          this.previousThemeId = themeId;
        }
      } else {
        if (this.previousThemeId !== 'default') {
          // No selected/preview client: fall back to domain theme (auth, unauthorized, etc.).
          this.cancelPendingThemeRequest$.next();
          this.updateTheme('default');
          this.previousThemeId = 'default';
        }

        this.previousClientId = undefined;
      }
    });
  }

  ngOnInit(): void {
    this.themeService.theme$
      .pipe(skip(1), takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (theme: ThemeResponse | null) => {
          // If no theme available (e.g., on context-selection page before client is selected),
          // hide the spinner to allow the underlying content to render
          if (!theme) {
            this.loading.set(false);
            return;
          }

          this.loadTheme(theme).catch((error) =>
            console.error('Error loading theme:', error),
          );
        },
        error: (err) => {
          this.loading.set(false);
          console.error('Error fetching theme:', err);
        },
      });
  }

  async loadTheme(theme: ThemeResponse): Promise<void> {
    const timer = setTimeout(
      () => this.loading.set(true),
      ThemeComponent.LOADING_DEBOUNCE_MS,
    );
    try {
      await this.processTheme(theme);
    } catch (error) {
      console.error('Theme loading error:', error);
    } finally {
      clearTimeout(timer);
      this.loading.set(false);
    }
  }

  private processCustomTags(theme: ThemeResponse): void {
    if (!theme.customTags) return;

    let index = 0;
    for (const customTag of theme.customTags) {
      this.appendHTML(
        `custom-tag-${index}`,
        customTag.location,
        customTag.tag,
        customTag.attributes,
        customTag.contents,
      );
      index++;
    }
  }

  private async processThemeVariables(theme: ThemeResponse): Promise<void> {
    if (!theme.variables) return;
    await this.injectSettingsVariables(theme.variables);
    this.updateClasses(theme.variables);
  }

  private async processTheme(theme: ThemeResponse): Promise<void> {
    await Promise.allSettled([
      this.withTimeout(
        this.processThemeVariables(theme),
        ThemeComponent.THEME_OPERATION_TIMEOUT_MS,
        'processThemeVariables',
      ),
      this.withTimeout(
        this.loadExternalStyles(theme),
        ThemeComponent.THEME_OPERATION_TIMEOUT_MS,
        'loadExternalStyles',
      ),
      this.withTimeout(
        this.injectCustomStyles(theme),
        ThemeComponent.THEME_OPERATION_TIMEOUT_MS,
        'injectCustomStyles',
      ),
      Promise.resolve(this.processCustomTags(theme)),
    ]);
  }

  private async withTimeout<T>(
    operation: Promise<T>,
    timeoutMs: number,
    operationName: string,
  ): Promise<T | void> {
    let timeoutId: ReturnType<typeof setTimeout> | undefined;

    try {
      return await Promise.race<T | void>([
        operation,
        new Promise<void>((resolve) => {
          timeoutId = setTimeout(() => {
            console.warn(
              `Theme operation timed out after ${timeoutMs}ms: ${operationName}`,
            );
            resolve();
          }, timeoutMs);
        }),
      ]);
    } finally {
      if (timeoutId) {
        clearTimeout(timeoutId);
      }
    }
  }

  private async loadExternalStyles(theme: ThemeResponse): Promise<void> {
    if (!theme.settings?.['cssSrc']) return;

    try {
      const response = await firstValueFrom(
        this.http.get(theme.settings['cssSrc'] as unknown as string, {
          responseType: 'text',
        }),
      );
      await this.injectStyle('external-css', response);
    } catch (error) {
      console.error('Failed to load external styles:', error);
    }
  }

  private async injectCustomStyles(theme: ThemeResponse): Promise<void> {
    if (isNullOrUndefined(theme.customStyles)) return;

    try {
      await this.injectStyle('custom-css', theme.customStyles);
    } catch (error) {
      console.error('Failed to inject custom styles:', error);
    }
  }

  private updateClasses(variables: Record<string, string>): void {
    const classes = [];

    if (
      variables['--main-gutter-width'] &&
      !['0', '0px', '0rem'].includes(variables['--main-gutter-width'])
    ) {
      classes.push('app-has-gutter');
    }

    this.classes = classes.join(' ');
  }

  private updateTheme(themeId: string): void {
    (themeId === 'default'
      ? this.themeService.getDomainTheme(this.currentHostname)
      : this.themeService.fetchTheme(themeId)
    )
      .pipe(take(1), takeUntil(this.cancelPendingThemeRequest$))
      .subscribe({
        next: (theme) => {
          this.themeService.setTheme(theme);
        },
        error: (err) => {
          console.error(`Failed to load theme ${themeId}:`, err);
        },
      });
  }

  private getThemeId(selectedClient: Partial<ClientResponse> | null): string {
    return isDefined(selectedClient?.theme?.id) &&
      selectedClient.theme.id !== 'inherited'
      ? selectedClient.theme.id
      : 'default';
  }

  async injectSettingsVariables(
    variables: Record<string, string>,
  ): Promise<void> {
    const fonts: Record<string, string> = {};
    const fontKeys = Object.keys(variables).filter((x) =>
      x.includes('-font-family'),
    );
    for (const key of fontKeys) {
      const font = variables[key];
      fonts[font] = `${font}:300,400,400i,500,700`;
    }
    if (Object.values(fonts).length > 0) {
      await this.loadFonts(fonts);
    }

    const cssVars = await import('css-vars-ponyfill');

    return new Promise<void>((resolve, reject) => {
      try {
        cssVars.default({
          variables: variables,
          onComplete() {
            resolve();
          },
          onError(message: string | undefined) {
            reject(new Error(message));
          },
        });
        if (this.hasNativeCssVariableSupport()) {
          resolve(); // cssVars will not trigger onComplete if the browser supports CSS variables
        }
      } catch (err) {
        reject(err instanceof Error ? err : new Error(String(err)));
      }
    });
  }

  async loadFonts(fonts: Record<string, string>): Promise<void> {
    const { default: WebFont } = await import('webfontloader');

    return new Promise<void>((resolve) => {
      let settled = false;
      const settle = () => {
        if (settled) return;
        settled = true;
        resolve();
      };

      const timeoutId = setTimeout(() => {
        console.warn('Font loading timed out; continuing with fallback fonts.');
        settle();
      }, ThemeComponent.FONT_LOAD_TIMEOUT_MS);

      try {
        WebFont.load({
          google: {
            families: Object.values(fonts),
          },
          active: () => {
            clearTimeout(timeoutId);
            settle();
          },
          inactive: () => {
            clearTimeout(timeoutId);
            settle();
          },
          fontactive: () => {
            clearTimeout(timeoutId);
            settle();
          },
          fontinactive: () => {
            clearTimeout(timeoutId);
            settle();
          },
        });
      } catch (err) {
        clearTimeout(timeoutId);
        console.warn(
          'WebFont loader failed; continuing with fallback fonts.',
          err,
        );
        settle();
      }
    });
  }

  async injectStyle(id: string, css: string): Promise<void> {
    try {
      let styleTag = this.document.getElementById(id) as HTMLStyleElement;
      if (isNullOrUndefined(styleTag)) {
        styleTag = this.renderer.createElement('style');
        this.renderer.setAttribute(styleTag, 'id', id);
        this.renderer.appendChild(this.document.head, styleTag);
      }
      styleTag.textContent = css;
    } catch (error) {
      console.error('Failed to inject style:', error);
      throw error;
    }
  }

  appendHTML(
    id: string,
    owner: string,
    tag: string,
    attributes: string,
    contents: string,
  ): void {
    const ALLOWED_ATTRS: Record<string, Set<string>> = {
      style: new Set(['id', 'type']),
      meta: new Set(['name', 'content', 'charset', 'http-equiv']),
      link: new Set(['rel', 'id', 'type', 'media']),
      // TODO(CHV-security): align with backend to remove script support or enforce src allowlisting
      script: new Set(['id', 'src', 'type', 'async', 'defer', 'crossorigin']),
    };

    const normalizedTag = tag.toLowerCase();
    if (!(normalizedTag in ALLOWED_ATTRS)) return;

    const parent = this.document.getElementsByTagName(owner)[0];
    const element = this.renderer.createElement(tag);
    this.renderer.setAttribute(element, 'id', id);
    const strings = (attributes || '')
      .split(/[\r\n]/g)
      .filter((x): boolean => !!x);
    for (const str of strings) {
      const [key, ...rest] = str.split('=');
      const normalizedKey = key.toLowerCase();
      if (!ALLOWED_ATTRS[normalizedTag].has(normalizedKey)) continue;
      if (
        normalizedTag === 'link' &&
        normalizedKey === 'rel' &&
        rest.join('=').replaceAll(/['"]/g, '').trim() !== 'stylesheet'
      )
        continue;
      this.renderer.setAttribute(
        element,
        key,
        rest.join('=').replaceAll(/['"]/g, '') || 'true',
      );
    }
    element.textContent = contents || '';
    this.renderer.appendChild(parent, element);
  }
}
